args.sqlite_command:
UPDATE J09B_enriched
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (SELECT EQUNR FROM J09B_mandatory_reading);

UPDATE J09B_enriched
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (SELECT EQUNR FROM J09B_direct_mail);

args.sql_query:
SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09B_enriched
WHERE ENTSCHEIDUNG NOT IN ('MANDATORY_READING', 'DIRECT_MAIL');
